import { v4 as uuidv4 } from 'uuid';
import CopyPaymentLink from "../SubscriptionSummary/CopyPaymentLink";
import { epochTogmt } from 'src/utils/Common';

export const tableTransactionHistoryConstant = (tableType) => {

    return tableType === "SUBSCRIPTION_HISTORY" ? 

    [
        {
            id: 1,
            name: "PRODUCT",
            selector: (row) => row?.product?.name,
            sortable: true,
            reorder: true,
        },
        {
            id: 2,
            name: "PLAN",
            selector: (row) => row?.plan?.subscriptionPlanType,
            sortable: true,
            reorder: true
        },
        {
            id: 3,
            name: "PATMENT TYPE",
            selector: (row) => row?.paymentReceiveType,
            sortable: true,
            reorder: true
        },
        {
            id: 4,
            name: "AMOUNT",
            selector: (row) => row?.baseAmount,
            sortable: true,
            reorder: true
        },
        {
            id: 5,
            name: "DISCOUNT",
            selector: (row) =>  row?.discount > 0 ? `${row?.discount}%` : "-",
            sortable: true,
            reorder: true
        },
        {
            id: 6,
            name: "NET AMOUNT",
            selector: (row) => row?.amount,
            sortable: true,
            reorder: true
        },
        {
            id: 7,
            name: "DESCRIPTION",
            selector: (row) => row?.description,
            sortable: true,
            reorder: true
        },
        {
            id: 8,
            name: "LINK",
            cell: (row) => {
                return (
                    <CopyPaymentLink paymentlink={row?.link} key={uuidv4()} />
                );
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 9,
            name: "STATUS",
            selector: (row) => row?.status,
            sortable: true,
            reorder: true
        },
    ]

    : 

    [
        {
            id: 1,
            name: "INVOICE UPLOAD DATE",
            selector: (row) => row?.invoiceDate ? epochTogmt(row.invoiceDate) : "-",
            sortable: true,
            reorder: true,
        },
        {
            id: 2,
            name: "INVOICE INFO",
            selector: (row) => row?.invoiceInfo,
            sortable: true,
            reorder: true
        },
        {
            id: 3,
            name: "INVOICE AMOUNT",
            selector: (row) => row?.invoiceAmount,
            sortable: true,
            reorder: true
        },
        // {
        //     id: 4,
        //     name: "INVOICE DOWNLOAD",
        //     selector: (row) => row?.paymentType ? row.paymentType : "-",
        //     sortable: true,
        //     reorder: true
        // }
    ]
};
